   179→        .orElseGet(() -> FxVanillaOption.of(longShort, expiry, ccyPair, putCall, strike, notional1, paymentDate));
   180→    return FxVanillaOptionTrade.builder()
   181→        .info(info)
   182→        .product(option)
   183→        .premium(CsvLoaderUtils.tryParsePremiumFromDefaultFields(row)
   184→            .orElse(AdjustablePayment.of(option.getCurrencyPair().getBase(), 0d, expiryDate)))
   185→        .build();
   186→  }
   187→
   188→  private static double parseStrike(CsvRow row, double notional1) {
   189→    Optional<Double> strikeOpt = row.findValue(STRIKE_FIELD, LoaderUtils::parseDouble);
   190→    if (strikeOpt.isPresent()) {
   191→      return strikeOpt.get();
   192→    } else {
   193→      double notional2 = row.getValue(LEG_2_NOTIONAL_FIELD, LoaderUtils::parseDouble);
   194→      return Math.abs(notional2 / notional1);
   195→    }
   196→  }
