   212→  protected void writeFxVanillaOption(CsvOutput.CsvRowOutputWithHeaders csv, FxVanillaOption product) {
   213→    FxSingle underlying = product.getUnderlying();
   214→    PutCall putCall = underlying.getCounterCurrencyPayment().getAmount() > 0d ? PutCall.PUT : PutCall.CALL;
   215→    double strike = Math.abs(underlying.getCounterCurrencyPayment().getAmount() /
   216→        underlying.getBaseCurrencyPayment().getAmount());
   217→    csv.writeCell(LONG_SHORT_FIELD, product.getLongShort());
   218→    csv.writeCell(PUT_CALL_FIELD, putCall);
   219→    csv.writeCell(STRIKE_FIELD, strike);
   220→    csv.writeCell(EXPIRY_DATE_FIELD, product.getExpiryDate());
   221→    csv.writeCell(EXPIRY_TIME_FIELD, product.getExpiryTime());
   222→    csv.writeCell(EXPIRY_ZONE_FIELD, product.getExpiryZone());
   223→    csv.writeCell(LEG_1_CURRENCY_FIELD, underlying.getBaseCurrencyPayment().getCurrency());
   224→    csv.writeCell(LEG_1_NOTIONAL_FIELD, Math.abs(underlying.getBaseCurrencyPayment().getAmount()));
   225→    csv.writeCell(LEG_2_CURRENCY_FIELD, underlying.getCounterCurrencyPayment().getCurrency());
   226→    csv.writeCell(PAYMENT_DATE_FIELD, underlying.getBaseCurrencyPayment().getDate());
   227→    underlying.getPaymentDateAdjustment().ifPresent(bda -> {
   228→      csv.writeCell(PAYMENT_DATE_CAL_FIELD, bda.getCalendar());
   229→      csv.writeCell(PAYMENT_DATE_CNV_FIELD, bda.getConvention());
   230→    });
